mapper.select:
SELECT * FROM ( SELECT A.*, ROWNUM AS RNUM FROM ( SELECT LAWYER_ID, NAME, NAME_EN, BAR_NUMBER, EMAIL, PHONE, SPECIALTY, EDUCATION, CAREER, INTRODUCTION, STATUS, ADMISSION_DATE, CREATED_AT, UPDATED_AT FROM TB_LAWYER WHERE 2=2
AND ( NAME LIKE '%' || #{searchKeyword} || '%' OR SPECIALTY LIKE '%' || #{searchKeyword} || '%' OR CAREER LIKE '%' || #{searchKeyword} || '%' )
AND STATUS = #{status}
ORDER BY LAWYER_ID DESC ) A WHERE ROWNUM <= #{pageNo} * #{pageSize} ) WHERE RNUM > (#{pageNo} - 1) * #{pageSize}

SELECT COUNT(*) FROM TB_LAWYER WHERE 1=1
AND ( NAME LIKE '%' || #{searchKeyword} || '%' OR SPECIALTY LIKE '%' || #{searchKeyword} || '%' OR CAREER LIKE '%' || #{searchKeyword} || '%' )
AND STATUS = #{status}
